const q = $input.first().json.query || {};
const body = $input.first().json.body || {};
const nip = (q.nip || body.nip || '').replace(/'/g,"''");
const userId = (q.user_id || body.user_id || '').replace(/'/g,"''");
const role = (q.role || body.role || 'USER').replace(/'/g,"''");
const instansiId = (q.instansi_id || body.instansi_id || '').replace(/'/g,"''");
const action = (q.action || body.action || 'login').replace(/'/g,"''");
const sessionToken = (q.session_token || body.session_token || '').replace(/'/g,"''");
if (action === 'login' && !nip) {
  return [{ json: { ok: false, message: 'NIP required' } }];
}
return [{ json: { action, nip, user_id: userId, role, instansi_id: instansiId, session_token: sessionToken } }];

const d = $input.first().json;
if (d.action === 'login') {
  return [{ json: { sql: `SELECT create_session('${d.nip}','${d.user_id}','${d.role}','${d.instansi_id}') AS session_token;` } }];
} else {
  return [{ json: { sql: `UPDATE auth_sessions SET is_active=false WHERE session_token='${d.session_token}';` } }];
}

const d = $input.first().json;
if (d.session_token) {
  return [{ json: { ok: true, session_token: d.session_token } }];
}
return [{ json: { ok: false, message: 'Session creation failed' } }];
